window.PACTO.acts["dir-2013-33"]={"label": "DIRETTIVA 2013/33/UE DEL PARLAMENTO EUROPEO E DEL CONSIGLIO", "short": "Dir. 33/2013", "file": "ext-dir-2013-33.html", "external": true, "version": "originale GU", "eurlex": "https://eur-lex.europa.eu/eli/dir/2013/33/oj/ita", "articles": {"1": {"label": "Articolo 1", "heading": "Scopo", "anchor": "art_1", "frags": [[null, "<p class=\"oj-normal\">La presente direttiva stabilisce norme relative all’accoglienza dei richiedenti protezione internazionale («richiedenti») negli Stati membri.</p>"]]}, "2": {"label": "Articolo 2", "heading": "Definizioni", "anchor": "art_2", "frags": [[null, "<p class=\"oj-normal\">Ai fini della presente direttiva si intende per:</p>"], [null, "<p class=\"oj-normal\">a)   <span class=\"oj-bold\">«domanda di protezione internazionale»</span>: la domanda di protezione internazionale quale definita all’articolo 2, lettera h), della direttiva 2011/95/UE;</p>"], [null, "<p class=\"oj-normal\">b)   <span class=\"oj-bold\">«richiedente»</span>: il cittadino di un paese terzo o apolide che abbia presentato una domanda di protezione internazionale sulla quale non è stata ancora adottata una decisione definitiva;</p>"], [null, "<p class=\"oj-normal\">c)   </p>"], [null, "<span class=\"oj-bold\">«familiari»</span>"], [null, "<p class=\"oj-normal\">: i seguenti soggetti appartenenti alla famiglia del richiedente, purché essa sia già costituita nel paese di origine, che si trovano nel medesimo Stato membro in connessione alla domanda di protezione internazionale:\n                           </p>"], [null, "<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">—</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">il coniuge del richiedente o il partner non legato da vincoli di matrimonio che abbia una relazione stabile con il richiedente, qualora il diritto o la prassi dello Stato membro interessato assimili la situazione delle coppie di fatto a quelle sposate nel quadro della legge sui cittadini di paesi terzi,</p>\n</td>\n</tr>\n</tbody>\n</table>"], [null, "<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">—</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">i figli minori delle coppie di cui al primo trattino o del richiedente, a condizione che non siano coniugati e, indipendentemente dal fatto che siano figli legittimi, naturali o adottivi secondo le definizioni del diritto nazionale,</p>\n</td>\n</tr>\n</tbody>\n</table>"], [null, "<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">—</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">il padre, la madre o un altro adulto responsabile per il richiedente in base alla legge o alla prassi dello Stato membro interessato,nei casi in cui detto richiedente è minore e non coniugato,</p>\n</td>\n</tr>\n</tbody>\n</table>"], [null, "<p class=\"oj-normal\">d)   <span class=\"oj-bold\">«minore»</span>: il cittadino di un paese terzo o l’apolide d’età inferiore agli anni diciotto;</p>"], [null, "<p class=\"oj-normal\">e)   <span class=\"oj-bold\">«minore non accompagnato»</span>: il minore che entri nel territorio degli Stati membri senza essere accompagnato da un adulto che ne sia responsabile per legge o per prassi dello Stato membro interessato, fino a quando non sia effettivamente affidato a un tale adulto; il termine include il minore che viene abbandonato dopo essere entrato nel territorio degli Stati membri;</p>"], [null, "<p class=\"oj-normal\">f)   <span class=\"oj-bold\">«condizioni di accoglienza»</span>: il complesso delle misure garantite dagli Stati membri a favore dei richiedenti ai sensi della presente direttiva;</p>"], [null, "<p class=\"oj-normal\">g)   <span class=\"oj-bold\">«condizioni materiali di accoglienza»</span>: le condizioni di accoglienza che includono alloggio, vitto e vestiario, forniti in natura o in forma di sussidi economici o buoni, o una combinazione delle tre possibilità, nonché un sussidio per le spese giornaliere;</p>"], [null, "<p class=\"oj-normal\">h)   <span class=\"oj-bold\">«trattenimento»</span>: il confinamento del richiedente, da parte di uno Stato membro, in un luogo determinato, che lo priva della libertà di circolazione;</p>"], [null, "<p class=\"oj-normal\">i)   <span class=\"oj-bold\">«centro di accoglienza»</span>: qualsiasi struttura destinata all’alloggiamento collettivo di richiedenti;</p>"], [null, "<p class=\"oj-normal\">j)   <span class=\"oj-bold\">«rappresentante»</span>: la persona o l’organizzazione designata dagli organismi competenti per assistere e rappresentare il minore non accompagnato nelle procedure previste dalla presente direttiva, allo scopo di garantirne l’interesse superiore del minore ed esercitare la capacità di agire per suo conto, ove necessario. L’organizzazione designata come rappresentante nomina una persona responsabile di assolverne le funzioni nei confronti del minore non accompagnato, in conformità della presente direttiva;</p>"], [null, "<p class=\"oj-normal\">k)   <span class=\"oj-bold\">«richiedente con esigenze di accoglienza particolari»</span>: una persona vulnerabile ai sensi dell’articolo 21, che necessita di garanzie particolari per godere dei diritti e adempiere gli obblighi previsti dalla presente direttiva.</p>"]]}, "3": {"label": "Articolo 3", "heading": "Ambito di applicazione", "anchor": "art_3", "frags": [[1, "<div>\n<p class=\"oj-normal\">1.   La presente direttiva si applica a tutti i cittadini di paesi terzi e agli apolidi che manifestano la volontà di chiedere la protezione internazionale nel territorio di uno Stato membro, comprese la frontiera, le acque territoriali o le zone di transito, purché siano autorizzati a soggiornare in tale territorio in qualità di richiedenti, nonché ai familiari, se inclusi nella domanda di protezione internazionale ai sensi del diritto nazionale.</p>\n</div>"], [2, "<div>\n<p class=\"oj-normal\">2.   La presente direttiva non si applica alle domande di asilo diplomatico o territoriale presentate presso le rappresentanze degli Stati membri.</p>\n</div>"], [3, "<div>\n<p class=\"oj-normal\">3.   La presente direttiva non si applica quando si applicano le disposizioni della direttiva 2001/55/CE del Consiglio, del 20 luglio 2001, sulle norme minime per la concessione della protezione temporanea in caso di afflusso massiccio di sfollati e sulla promozione dell’equilibrio degli sforzi tra gli Stati membri che ricevono gli sfollati e subiscono le conseguenze dell’accoglienza degli stessi (<span class=\"oj-super oj-note-tag\">7</span>).</p>\n</div>"], [4, "<div>\n<p class=\"oj-normal\">4.   Gli Stati membri possono decidere di applicare la presente direttiva in relazione a procedimenti di esame di domande intese a ottenere forme di protezione diverse da quella conferita dalla direttiva 2011/95/UE.</p>\n</div>"]]}, "4": {"label": "Articolo 4", "heading": "Disposizioni più favorevoli", "anchor": "art_4", "frags": [[null, "<p class=\"oj-normal\">Gli Stati membri possono stabilire o mantenere in vigore disposizioni più favorevoli sulle condizioni di accoglienza dei richiedenti e di parenti stretti dei richiedenti presenti nello stesso Stato membro quando siano a loro carico, oppure per motivi umanitari, purché tali disposizioni siano compatibili con la presente direttiva.</p>"]]}, "5": {"label": "Articolo 5", "heading": "Informazione", "anchor": "art_5", "frags": [[1, "<div>\n<p class=\"oj-normal\">1.   Gli Stati membri informano i richiedenti, entro un termine ragionevole non superiore a quindici giorni dopo la presentazione della domanda di protezione internazionale, almeno di qualsiasi beneficio riconosciuto e degli obblighi loro spettanti in riferimento alle condizioni di accoglienza.</p>\n<p class=\"oj-normal\">Gli Stati membri provvedono a che i richiedenti siano informati sulle organizzazioni o sui gruppi di persone che forniscono specifica assistenza legale e sulle organizzazioni che possono aiutarli o informarli riguardo alle condizioni di accoglienza disponibili, compresa l’assistenza sanitaria.</p>\n</div>"], [2, "<div>\n<p class=\"oj-normal\">2.   Gli Stati membri provvedono a che le informazioni di cui al paragrafo 1 siano fornite per iscritto e in una lingua che il richiedente comprende o che ragionevolmente si suppone a lui comprensibile. Se del caso, tali informazioni possono anche essere fornite oralmente.</p>\n</div>"]]}, "6": {"label": "Articolo 6", "heading": "Documentazione", "anchor": "art_6", "frags": [[1, "<div>\n<p class=\"oj-normal\">1.   Gli Stati membri provvedono affinché, entro tre giorni dalla presentazione della domanda di protezione internazionale, ai richiedenti sia rilasciato un documento nominativo che certifichi lo status di richiedente o che attesti che il richiedente è autorizzato a soggiornare nel territorio dello Stato membro nel periodo in cui la domanda è pendente o in esame.</p>\n<p class=\"oj-normal\">Per i titolari che non possono circolare liberamente in tutto il territorio dello Stato membro o in una parte di esso, il documento attesta altresì questa situazione.</p>\n</div>"], [2, "<div>\n<p class=\"oj-normal\">2.   Gli Stati membri possono escludere l’applicazione del presente articolo quando il richiedente è in stato di trattenimento e durante l’esame della domanda di protezione internazionale presentata alla frontiera o nel contesto di un procedimento volto a determinare se il richiedente abbia il diritto di entrare nel territorio di uno Stato membro. In determinati casi, durante l’esame della domanda di protezione internazionale, gli Stati membri possono rilasciare ai richiedenti altre prove documentali equivalenti al documento di cui al paragrafo 1.</p>\n</div>"], [3, "<div>\n<p class=\"oj-normal\">3.   Il documento di cui al paragrafo 1 non certifica necessariamente l’identità del richiedente.</p>\n</div>"], [4, "<div>\n<p class=\"oj-normal\">4.   Gli Stati membri adottano le misure necessarie per rilasciare ai richiedenti il documento di cui al paragrafo 1, che deve essere valido finché sono autorizzati a restare nel territorio dello Stato membro interessato.</p>\n</div>"], [5, "<div>\n<p class=\"oj-normal\">5.   Gli Stati membri possono fornire ai richiedenti un documento di viaggio quando sussistano gravi ragioni umanitarie che ne rendano necessaria la presenza in un altro Stato.</p>\n</div>"], [6, "<div>\n<p class=\"oj-normal\">6.   Gli Stati membri non esigono documenti inutili o sproporzionati né impongono altri requisiti amministrativi ai richiedenti prima di riconoscere loro i diritti conferiti dalla presente direttiva, per il solo fatto che chiedono protezione internazionale.</p>\n</div>"]]}, "7": {"label": "Articolo 7", "heading": "Residenza e libera circolazione", "anchor": "art_7", "frags": [[1, "<div>\n<p class=\"oj-normal\">1.   I richiedenti possono circolare liberamente nel territorio dello Stato membro ospitante o nell’area loro assegnata da tale Stato membro. L’area assegnata non pregiudica la sfera inalienabile della vita privata e permette un campo d’azione sufficiente a garantire l’accesso a tutti i benefici della presente direttiva.</p>\n</div>"], [2, "<div>\n<p class=\"oj-normal\">2.   Gli Stati membri possono stabilire un luogo di residenza per il richiedente, per motivi di pubblico interesse, ordine pubblico o, ove necessario, per il trattamento rapido e il controllo efficace della domanda di protezione internazionale.</p>\n</div>"], [3, "<div>\n<p class=\"oj-normal\">3.   Gli Stati membri possono subordinare la concessione delle condizioni materiali d’accoglienza all’effettiva residenza del richiedente in un determinato luogo, da determinarsi dagli Stati membri. Tale decisione, che può essere di carattere generale, è adottata caso per caso e definita dalla diritto nazionale.</p>\n</div>"], [4, "<div>\n<p class=\"oj-normal\">4.   Gli Stati membri prevedono la possibilità di concedere ai richiedenti un permesso temporaneo di allontanarsi dal luogo di residenza di cui ai paragrafi 2 e 3 e/o dall’area assegnata di cui al paragrafo 1. Le decisioni sono adottate caso per caso, in modo obiettivo ed imparziale e sono motivate qualora siano negative.</p>\n<p class=\"oj-normal\">Il richiedente non necessita di permesso per presentarsi dinanzi alle autorità e ai giudici se è necessaria la sua comparizione.</p>\n</div>"], [5, "<div>\n<p class=\"oj-normal\">5.   Gli Stati membri fanno obbligo ai richiedenti di comunicare il loro indirizzo alle autorità competenti e di notificare loro con la massima tempestività qualsiasi sua successiva modificazione.</p>\n</div>"]]}, "8": {"label": "Articolo 8", "heading": "Trattenimento", "anchor": "art_8", "frags": [[1, "<div>\n<p class=\"oj-normal\">1.   Gli Stati membri non trattengono una persona per il solo fatto di essere un richiedente ai sensi della direttiva 2013/32/UE del Parlamento europeo e del Consiglio, del 26 giugno 2013, recante procedure comuni ai fini del riconoscimento e della revoca dello status di protezione internazionale (<span class=\"oj-super oj-note-tag\">8</span>).</p>\n</div>"], [2, "<div>\n<p class=\"oj-normal\">2.   Ove necessario e sulla base di una valutazione caso per caso, gli Stati membri possono trattenere il richiedente, salvo se non siano applicabili efficacemente misure alternative meno coercitive.</p>\n</div>"], [3, "<div>\n<p class=\"oj-normal\">3.   Un richiedente può essere trattenuto soltanto:</p>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">a)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">per determinarne o verificarne l’identità o la cittadinanza;</p>\n</td>\n</tr>\n</tbody>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">b)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">per determinare gli elementi su cui si basa la domanda di protezione internazionale che non potrebbero ottenersi senza il trattenimento, in particolare se sussiste il rischio di fuga del richiedente;</p>\n</td>\n</tr>\n</tbody>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">c)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">per decidere, nel contesto di un procedimento, sul diritto del richiedente di entrare nel territorio;</p>\n</td>\n</tr>\n</tbody>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">d)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">quando la persona è trattenuta nell’ambito di una procedura di rimpatrio ai sensi della direttiva 2008/115/CE del Parlamento europeo e del Consiglio, del 16 dicembre 2008, recante norme e procedure comuni applicabili negli Stati membri al rimpatrio di cittadini di paesi terzi il cui soggiorno è irregolare (<span class=\"oj-super oj-note-tag\">9</span>), al fine di preparare il rimpatrio e/o effettuare l’allontanamento e lo Stato membro interessato può comprovare, in base a criteri obiettivi, tra cui il fatto che la persona in questione abbia già avuto l’opportunità di accedere alla procedura di asilo, che vi sono fondati motivi per ritenere che la persona abbia manifestato la volontà di presentare la domanda di protezione internazionale al solo scopo di ritardare o impedire l’esecuzione della decisione di rimpatrio;</p>\n</td>\n</tr>\n</tbody>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">e)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">quando lo impongono motivi di sicurezza nazionale o di ordine pubblico;</p>\n</td>\n</tr>\n</tbody>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">f)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">conformemente all’articolo 28 del regolamento (UE) n. 604/2013 del Parlamento europeo e del Consiglio, del 26 giugno 2013, che stabilisce i criteri e i meccanismi di determinazione dello Stato membro competente per l’esame di una domanda di protezione internazionale presentata in uno degli Stati membri da un cittadino di un paese terzo o da un apolide (<span class=\"oj-super oj-note-tag\">10</span>).</p>\n</td>\n</tr>\n</tbody>\n</table>\n<p class=\"oj-normal\">I motivi di trattenimento sono specificati nel diritto nazionale.</p>\n</div>"], [4, "<div>\n<p class=\"oj-normal\">4.   Gli Stati membri provvedono affinché il diritto nazionale contempli le disposizioni alternative al trattenimento, come l’obbligo di presentarsi periodicamente alle autorità, la costituzione di una garanzia finanziaria o l’obbligo di dimorare in un luogo assegnato.</p>\n</div>"]]}, "9": {"label": "Articolo 9", "heading": "Garanzie per i richiedenti trattenuti", "anchor": "art_9", "frags": [[1, "<div>\n<p class=\"oj-normal\">1.   Un richiedente è trattenuto solo per un periodo il più breve possibile ed é mantenuto in stato di trattenimento soltanto fintantoché sussistono i motivi di cui all’articolo 8, paragrafo 3.</p>\n<p class=\"oj-normal\">Gli adempimenti amministrativi inerenti ai motivi di trattenimento di cui all’articolo 8, paragrafo 3, sono espletati con la debita diligenza. I ritardi nelle procedure amministrative non imputabili al richiedente non giustificano un prolungamento del trattenimento.</p>\n</div>"], [2, "<div>\n<p class=\"oj-normal\">2.   Il trattenimento dei richiedenti è disposto per iscritto dall’autorità giurisdizionale o amministrativa. Il provvedimento di trattenimento precisa le motivazioni di fatto e di diritto sulle quasi si basa.</p>\n</div>"], [3, "<div>\n<p class=\"oj-normal\">3.   Se il trattenimento è disposto dall’autorità amministrativa, gli Stati membri assicurano una rapida verifica in sede giudiziaria, d’ufficio e/o su domanda del richiedente, della legittimità del trattenimento. Se effettuata d’ufficio, tale verifica è disposta il più rapidamente possibile a partire dall’inizio del trattenimento stesso. Se effettuata su domanda del richiedente, è disposta il più rapidamente possibile dopo l’avvio del relativo procedimento. A tal fine, gli Stati membri stabiliscono nel diritto nazionale il termine entro il quale effettuare la verifica in sede giudiziaria d’ufficio e/o su domanda del richiedente.</p>\n<p class=\"oj-normal\">Se in seguito a una verifica in sede giudiziaria il trattenimento è ritenuto illegittimo, il richiedente interessato è rilasciato immediatamente.</p>\n</div>"], [4, "<div>\n<p class=\"oj-normal\">4.   I richiedenti trattenuti sono informati immediatamente per iscritto, in una lingua che essi comprendono o che ragionevolmente si suppone a loro comprensibile, delle ragioni del trattenimento e delle procedure previste dal diritto nazionale per contestare il provvedimento di trattenimento, nonché della possibilità di accesso gratuito all’assistenza e/o alla rappresentanza legali.</p>\n</div>"], [5, "<div>\n<p class=\"oj-normal\">5.   Il provvedimento di trattenimento è riesaminato da un’autorità giurisdizionale a intervalli ragionevoli, d’ufficio e/o su richiesta del richiedente in questione, in particolare nel caso di periodi di trattenimento prolungati, qualora si verifichino circostanze o emergano nuove informazioni che possano mettere in discussione la legittimità del trattenimento.</p>\n</div>"], [6, "<div>\n<p class=\"oj-normal\">6.   Nei casi di verifica in sede giudiziaria del provvedimento di trattenimento di cui al paragrafo 3, gli Stati membri provvedono affinché i richiedenti abbiano accesso gratuito all’assistenza e alla rappresentanza legali.Ciò comprende, come minimo, la preparazione dei documenti procedurali necessari e la partecipazione all’udienza dinanzi alle autorità giurisdizionali a nome del richiedente.</p>\n<p class=\"oj-normal\">L’assistenza e la rappresentanza legali gratuite sono prestate da persone adeguatamente qualificate, autorizzate o riconosciute ai sensi del diritto nazionale, i cui interessi non contrastano o non possono potenzialmente contrastare con quelli del richiedente.</p>\n</div>"], [7, "<div>\n<p class=\"oj-normal\">7.   Gli Stati membri possono anche disporre che l’assistenza e la rappresentanza legali gratuite siano concesse:</p>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">a)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">soltanto a chi non disponga delle risorse necessarie; e/o</p>\n</td>\n</tr>\n</tbody>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">b)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">soltanto mediante i servizi forniti da avvocati o altri consulenti legali che sono specificamente designati dal diritto nazionale ad assistere e rappresentare i richiedenti.</p>\n</td>\n</tr>\n</tbody>\n</table>\n</div>"], [8, "<div>\n<p class=\"oj-normal\">8.   Gli Stati membri possono altresì:</p>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">a)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">imporre limiti monetari e/o temporali alla prestazione di assistenza e rappresentanza legali gratuite, purché essi non restringano arbitrariamente l’assistenza e la rappresentanza legali;</p>\n</td>\n</tr>\n</tbody>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">b)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">prevedere, per quanto riguarda gli onorari e le altre spese, che il trattamento concesso ai richiedenti non sia più favorevole di quello di norma concesso ai propri cittadini per questioni che rientrano nell’assistenza legale.</p>\n</td>\n</tr>\n</tbody>\n</table>\n</div>"], [9, "<div>\n<p class=\"oj-normal\">9.   Gli Stati membri possono esigere un rimborso integrale o parziale delle spese sostenute, allorché vi sia stato un considerevole miglioramento delle condizioni finanziarie del richiedente o se la decisione di accordare tali prestazioni è stata adottata in base a informazioni false fornite dal richiedente.</p>\n</div>"], [10, "<div>\n<p class=\"oj-normal\">10.   Le modalità di accesso all’assistenza e alla rappresentanza legali sono stabilite dal diritto nazionale.</p>\n</div>"]]}, "10": {"label": "Articolo 10", "heading": "Condizioni di trattenimento", "anchor": "art_10", "frags": [[1, "<div>\n<p class=\"oj-normal\">1.   Il trattenimento dei richiedenti ha luogo, di regola, in appositi centri di trattenimento. Lo Stato membro che non possa ospitare il richiedente in un apposito centro di trattenimento e sia obbligato a sistemarlo in un istituto penitenziario, provvede affinché il richiedente trattenuto sia tenuto separato dai detenuti ordinari e siano applicate le condizioni di trattenimento previste dalla presente direttiva.</p>\n<p class=\"oj-normal\">Per quanto possibile, i richiedenti sono tenuti separati dai cittadini di paesi terzi che non hanno presentato domanda di protezione internazionale.</p>\n<p class=\"oj-normal\">Quando i richiedenti non possono essere tenuti separati da altri cittadini di paesi terzi, lo Stato membro interessato provvede affinché siano applicate le condizioni di trattenimento previste dalla presente direttiva.</p>\n</div>"], [2, "<div>\n<p class=\"oj-normal\">2.   I richiedenti trattenuti hanno accesso a spazi all’aria aperta.</p>\n</div>"], [3, "<div>\n<p class=\"oj-normal\">3.   Gli Stati membri garantiscono ai rappresentanti dell’Alto Commissariato delle Nazioni Unite per i Rifugiati (UNHCR) la possibilità di comunicare con i richiedenti e di rendere loro visita in condizioni che rispettano la vita privata. Tale possibilità si applica alle organizzazioni che operano nel territorio dello Stato membro interessato per conto dell’UNHCR, conformemente a un accordo con detto Stato membro.</p>\n</div>"], [4, "<div>\n<p class=\"oj-normal\">4.   Gli Stati membri garantiscono ai familiari, avvocati o consulenti legali e rappresentanti di organizzazioni non governative competenti riconosciute dallo Stato membro interessato la possibilità di comunicare con i richiedenti e di rendere loro visita in condizioni che rispettano la vita privata. Possono essere imposte limitazioni all’accesso al centro di trattenimento soltanto se obiettivamente necessarie, in virtù del diritto nazionale, per la sicurezza, l’ordine pubblico o la gestione amministrativa del centro di trattenimento, e purché non restringano drasticamente o rendano impossibile l’accesso.</p>\n</div>"], [5, "<div>\n<p class=\"oj-normal\">5.   Gli Stati membri provvedono affinché i richiedenti trattenuti siano sistematicamente informati delle norme vigenti nel centro e dei loro diritti e obblighi in una lingua che essi comprendono o che ragionevolmente si suppone a loro comprensibile. Gli Stati membri possono derogare a tale obbligo in casi debitamente giustificati e per un periodo ragionevole di durata più breve possibile, qualora i richiedenti siano trattenuti in un posto di frontiera o in una zona di transito. Tale deroga non si applica nei casi di cui all’articolo 43 della direttiva 2013/32/UE.</p>\n</div>"]]}, "11": {"label": "Articolo 11", "heading": "Trattenimento di persone vulnerabili e di richiedenti con esigenze di accoglienza particolari", "anchor": "art_11", "frags": [[1, "<div>\n<p class=\"oj-normal\">1.   Lo stato di salute, anche mentale, dei richiedenti trattenuti che sono persone vulnerabili costituisce la preoccupazione principale delle autorità nazionali.</p>\n<p class=\"oj-normal\">Alle persone vulnerabili trattenute gli Stati membri assicurano controlli periodici e sostegno adeguato tenendo conto della loro particolare situazione, anche dal punto di vista sanitario.</p>\n</div>"], [2, "<div>\n<p class=\"oj-normal\">2.   I minori sono trattenuti solo come ultima risorsa e dopo aver accertato che misure alternative meno coercitive non possono essere applicate in maniera efficace. A tale trattenimento deve farsi ricorso per un periodo di durata più breve possibile ed è fatto il possibile perché siano rilasciati e ospitati in alloggi idonei per i minori.</p>\n<p class=\"oj-normal\">L’interesse superiore del minore, come prescritto all’articolo 23, paragrafo 2, deve essere una considerazione preminente per gli Stati membri.</p>\n<p class=\"oj-normal\">I minori trattenuti devono potere avere la possibilità di svolgere attività di tempo libero, compresi il gioco e attività ricreative consone alla loro età.</p>\n</div>"], [3, "<div>\n<p class=\"oj-normal\">3.   I minori non accompagnati sono trattenuti solo in circostanze eccezionali. È fatto il possibile affinché i minori non accompagnati trattenuti siano rilasciati il più rapidamente possibile.</p>\n<p class=\"oj-normal\">I minori non accompagnati non sono mai trattenuti in istituti penitenziari.</p>\n<p class=\"oj-normal\">Per quanto possibile, ai minori non accompagnati deve essere fornita una sistemazione in istituti dotati di personale e strutture consoni a soddisfare le esigenze di persone della loro età.</p>\n<p class=\"oj-normal\">Ai minori non accompagnati trattenuti gli Stati membri garantiscono una sistemazione separata dagli adulti.</p>\n</div>"], [4, "<div>\n<p class=\"oj-normal\">4.   Alle famiglie trattenute è fornita una sistemazione separata che ne tuteli l’intimità.</p>\n</div>"], [5, "<div>\n<p class=\"oj-normal\">5.   Alle richiedenti trattenute gli Stati membri garantiscono una sistemazione separata dai richiedenti uomini, salvo che si tratti di familiari e che tutti gli interessati vi acconsentano.</p>\n<p class=\"oj-normal\">Si possono applicare eccezioni al primo comma anche per l’uso degli spazi comuni destinati ad attività ricreative o sociali, compresa la fornitura dei pasti.</p>\n</div>"], [6, "<div>\n<p class=\"oj-normal\">6.   In casi debitamente giustificati e per un periodo ragionevole di durata più breve possibile, gli Stati membri possono derogare al paragrafo 2, terzo comma, al paragrafo 4 e al paragrafo 5, primo comma, se il richiedente è trattenuto in un posto di frontiera o in una zona di transito, fatti salvi i casi di cui all’articolo 43 della direttiva 2013/32/UE.</p>\n</div>"]]}, "12": {"label": "Articolo 12", "heading": "Nucleo familiare", "anchor": "art_12", "frags": [[null, "<p class=\"oj-normal\">Quando provvedono ad alloggiare il richiedente, gli Stati membri adottano misure idonee a mantenere nella misura del possibile l’unità del nucleo familiare presente nel loro territorio. Tali misure sono applicate con il consenso del richiedente.</p>"]]}, "13": {"label": "Articolo 13", "heading": "Esami medici", "anchor": "art_13", "frags": [[null, "<p class=\"oj-normal\">Gli Stati membri possono disporre che i richiedenti siano sottoposti a esame medico per ragioni di sanità pubblica.</p>"]]}, "14": {"label": "Articolo 14", "heading": "Scolarizzazione e istruzione dei minori", "anchor": "art_14", "frags": [[1, "<div>\n<p class=\"oj-normal\">1.   Gli Stati membri consentono ai figli minori di richiedenti e ai richiedenti minori di accedere al sistema educativo a condizioni simili a quelle dei propri cittadini, finché non sia concretamente eseguito un provvedimento di espulsione nei confronti loro o dei loro genitori. Tale istruzione può essere impartita nei centri di accoglienza.</p>\n<p class=\"oj-normal\">Gli Stati membri interessati possono stabilire che tale accesso sia limitato al sistema educativo pubblico.</p>\n<p class=\"oj-normal\">Gli Stati membri non revocano la possibilità di accedere all’istruzione secondaria per il solo fatto che il minore abbia raggiunto la maggiore età.</p>\n</div>"], [2, "<div>\n<p class=\"oj-normal\">2.   L’accesso al sistema educativo non è differito di oltre tre mesi dalla data di presentazione della domanda di protezione internazionale da parte o per conto del minore.</p>\n<p class=\"oj-normal\">Sono impartiti corsi di preparazione, anche di lingua, ai minori, se necessari per agevolarne l’accesso e la partecipazione al sistema educativo come stabilito al paragrafo 1.</p>\n</div>"], [3, "<div>\n<p class=\"oj-normal\">3.   Qualora l’accesso al sistema educativo previsto al paragrafo 1 non sia possibile a causa della situazione specifica del minore, lo Stato membro interessato offre altre modalità d’insegnamento conformemente al proprio diritto e alla propria prassi nazionali.</p>\n</div>"]]}, "15": {"label": "Articolo 15", "heading": "Lavoro", "anchor": "art_15", "frags": [[1, "<div>\n<p class=\"oj-normal\">1.   Gli Stati membri garantiscono l’accesso dei richiedenti al mercato del lavoro entro nove mesi dalla data di presentazione della domanda di protezione internazionale nei casi in cui l’autorità competente non abbia adottato una decisione in primo grado e il ritardo non possa essere attribuito al richiedente.</p>\n</div>"], [2, "<div>\n<p class=\"oj-normal\">2.   Gli Stati membri decidono a quali condizioni è concesso al richiedente l’accesso al mercato del lavoro conformemente al diritto nazionale, senza limitare indebitamente tale accesso</p>\n<p class=\"oj-normal\">Per ragioni connesse alle politiche del mercato del lavoro, gli Stati membri possono dare la precedenza ai cittadini dell’Unione e ai cittadini degli Stati parti dell’accordo sullo spazio economico europeo, nonché ai cittadini di paesi terzi in soggiorno regolare.</p>\n</div>"], [3, "<div>\n<p class=\"oj-normal\">3.   L’accesso al mercato del lavoro non è revocato durante i procedimenti di ricorso, quando un ricorso presentato avverso una decisione negativa adottata in esito ad un procedimento ordinario abbia effetto sospensivo, fino al momento della notifica della decisione negativa sul ricorso.</p>\n</div>"]]}, "16": {"label": "Articolo 16", "heading": "Formazione professionale", "anchor": "art_16", "frags": [[null, "<p class=\"oj-normal\">Gli Stati membri possono autorizzare l’accesso dei richiedenti alla formazione professionale indipendentemente dal fatto che abbiano accesso al mercato del lavoro.</p>"], [null, "<p class=\"oj-normal\">L’accesso alla formazione professionale collegata a un contratto di lavoro è subordinato alla possibilità, per il richiedente, di accedere al mercato del lavoro conformemente all’articolo 15.</p>"]]}, "17": {"label": "Articolo 17", "heading": "Disposizioni generali relative alle condizioni materiali di accoglienza e all’assistenza sanitaria", "anchor": "art_17", "frags": [[1, "<div>\n<p class=\"oj-normal\">1.   Gli Stati membri provvedono a che i richiedenti abbiano accesso alle condizioni materiali d’accoglienza nel momento in cui manifestano la volontà di chiedere la protezione internazionale.</p>\n</div>"], [2, "<div>\n<p class=\"oj-normal\">2.   Gli Stati membri provvedono a che le condizioni materiali di accoglienza assicurino un’adeguata qualità di vita che garantisca il sostentamento dei richiedenti e ne tuteli la salute fisica e mentale.</p>\n<p class=\"oj-normal\">Gli Stati membri provvedono a che la qualità di vita sia adeguata alla specifica situazione delle persone vulnerabili, ai sensi dell’articolo 21, nonché alla situazione delle persone che si trovano in stato di trattenimento.</p>\n</div>"], [3, "<div>\n<p class=\"oj-normal\">3.   Gli Stati membri possono subordinare la concessione di tutte le condizioni materiali d’accoglienza e dell’assistenza sanitaria, o di parte delle stesse, alla condizione che i richiedenti non dispongano di mezzi sufficienti a garantire loro una qualità della vita adeguata per la loro salute, nonché ad assicurare il loro sostentamento.</p>\n</div>"], [4, "<div>\n<p class=\"oj-normal\">4.   Gli Stati membri possono obbligare i richiedenti a sostenere o a contribuire a sostenere i costi delle condizioni materiali di accoglienza e dell’assistenza sanitaria previsti nella presente direttiva, ai sensi del paragrafo 3, qualora i richiedenti dispongano di sufficienti risorse, ad esempio qualora siano stati occupati per un ragionevole lasso di tempo.</p>\n<p class=\"oj-normal\">Qualora emerga che un richiedente disponeva di mezzi sufficienti ad assicurarsi le condizioni materiali di accoglienza e l’assistenza sanitaria all’epoca in cui tali esigenze essenziali sono state soddisfatte, gli Stati membri possono chiedere al richiedente un rimborso.</p>\n</div>"], [5, "<div>\n<p class=\"oj-normal\">5.   Qualora gli Stati membri forniscano le condizioni materiali di accoglienza in forma di sussidi economici o buoni, l’ammontare dei medesimi è fissato sulla base del livello o dei livelli stabiliti dallo Stato membro interessato, secondo la legge o la prassi, in modo da garantire una qualità di vita adeguata ai propri cittadini. Gli Stati membri possono accordare ai richiedenti un trattamento meno favorevole di quello che accordano ai loro cittadini, in particolare nei casi in cui un sostegno materiale è parzialmente fornito in natura o quando il livello o i livelli, applicati ai cittadini, sono intesi ad assicurare un tenore di vita più elevato di quello prescritto per i richiedenti ai sensi della presente direttiva.</p>\n</div>"]]}, "18": {"label": "Articolo 18", "heading": "Modalità relative alle condizioni materiali di accoglienza", "anchor": "art_18", "frags": [[1, "<div>\n<p class=\"oj-normal\">1.   Nel caso in cui l’alloggio è fornito in natura, esso dovrebbe essere concesso in una delle seguenti forme oppure mediante una combinazione delle stesse:</p>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">a)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">in locali utilizzati per alloggiare i richiedenti durante l’esame della domanda di protezione internazionale presentata alla frontiera o in zone di transito;</p>\n</td>\n</tr>\n</tbody>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">b)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">in centri di accoglienza che garantiscano una qualità di vita adeguata;</p>\n</td>\n</tr>\n</tbody>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">c)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">in case private, appartamenti, alberghi o altre strutture atte a garantire un alloggio per i richiedenti.</p>\n</td>\n</tr>\n</tbody>\n</table>\n</div>"], [2, "<div>\n<p class=\"oj-normal\">2.   Fatte salve le condizioni specifiche di trattenimento di cui agli articoli 10 e 11, in relazione agli alloggi di cui al paragrafo 1, lettere a), b) e c) del presente articolo, gli Stati membri provvedono affinché:</p>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">a)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">sia garantita ai richiedenti la tutela della vita familiare;</p>\n</td>\n</tr>\n</tbody>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">b)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">i richiedenti abbiano la possibilità di comunicare con i parenti, gli avvocati o i consulenti legali, i rappresentanti dell’UNHCR e altri organismi e organizzazioni nazionali, internazionali e non governativi competenti;</p>\n</td>\n</tr>\n</tbody>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">c)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">ai familiari, agli avvocati o ai consulenti legali nonché ai rappresentanti dell’UNHCR e di organizzazioni non governative competenti riconosciute dallo Stato membro interessato, sia consentito l’accesso al fine di assistere i richiedenti. Possono essere previste limitazioni dell’accesso soltanto per la sicurezza dei locali e dei richiedenti.</p>\n</td>\n</tr>\n</tbody>\n</table>\n</div>"], [3, "<div>\n<p class=\"oj-normal\">3.   Gli Stati membri tengono conto delle differenze di genere e di età e della situazione delle persone con esigenze particolari all’interno dei locali e dei centri di accoglienza di cui al paragrafo 1, lettere a) e b).</p>\n</div>"], [4, "<div>\n<p class=\"oj-normal\">4.   Gli Stati membri adottano le misure opportune per prevenire la violenza e la violenza di genere in particolare, compresa la violenza sessuale e le molestie, all’interno dei locali e dei centri di accoglienza di cui al paragrafo 1, lettere a) e b).</p>\n</div>"], [5, "<div>\n<p class=\"oj-normal\">5.   Gli Stati membri provvedono, per quanto possibile, che i richiedenti che sono adulti dipendenti con particolari esigenze di accoglienza siano alloggiati insieme a parenti stretti adulti già presenti nel medesimo Stato membro e che sono responsabili nei loro confronti in base alla legge o alla prassi dello Stato membro interessato.</p>\n</div>"], [6, "<div>\n<p class=\"oj-normal\">6.   Gli Stati membri provvedono a che i trasferimenti di richiedenti da una struttura alloggiativa a un’altra avvengano soltanto se necessari. Gli Stati membri dispongono che i richiedenti possano informare i loro avvocati o consulenti legali del trasferimento e del loro nuovo indirizzo.</p>\n</div>"], [7, "<div>\n<p class=\"oj-normal\">7.   Le persone che lavorano nei centri di accoglienza ricevono una formazione adeguata e sono soggette alle norme in materia di riservatezza previste dal diritto nazionale, in ordine alle informazioni di cui vengano a conoscenza nel corso della loro attività.</p>\n</div>"], [8, "<div>\n<p class=\"oj-normal\">8.   Gli Stati membri possono coinvolgere i richiedenti nella gestione delle risorse materiali e degli aspetti non materiali della vita nei centri attraverso comitati o consigli consultivi rappresentativi delle persone residenti.</p>\n</div>"], [9, "<div>\n<p class=\"oj-normal\">9.   In casi debitamente giustificati gli Stati membri possono stabilire in via eccezionale modalità relative alle condizioni materiali di accoglienza diverse da quelle previste nel presente articolo, per un periodo ragionevole e di durata più breve possibile, qualora:</p>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">a)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">sia richiesta una valutazione delle esigenze specifiche del richiedente, ai sensi dell’articolo 22,</p>\n</td>\n</tr>\n</tbody>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">b)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">le capacità di alloggio normalmente disponibili siano temporaneamente esaurite.</p>\n</td>\n</tr>\n</tbody>\n</table>\n<p class=\"oj-normal\">Siffatte diverse condizioni soddisfano comunque le esigenze essenziali.</p>\n</div>"]]}, "19": {"label": "Articolo 19", "heading": "Assistenza sanitaria", "anchor": "art_19", "frags": [[1, "<div>\n<p class=\"oj-normal\">1.   Gli Stati membri provvedono affinché i richiedenti ricevano la necessaria assistenza sanitaria che comprende quanto meno le prestazioni di pronto soccorso e il trattamento essenziale delle malattie e di gravi disturbi mentali.</p>\n</div>"], [2, "<div>\n<p class=\"oj-normal\">2.   Gli Stati membri forniscono la necessaria assistenza medica, o di altro tipo, ai richiedenti con esigenze di accoglienza particolari, comprese, se necessarie, appropriate misure di assistenza psichica.</p>\n</div>"]]}, "20": {"label": "Articolo 20", "heading": "Riduzione o revoca delle condizioni materiali di accoglienza", "anchor": "art_20", "frags": [[1, "<div>\n<p class=\"oj-normal\">1.   Gli Stati membri possono ridurre o, in casi eccezionali debitamente motivati, revocare le condizioni materiali di accoglienza qualora il richiedente:</p>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">a)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">lasci il luogo di residenza determinato dall’autorità competente senza informare tali autorità, oppure, ove richiesto, senza permesso; o</p>\n</td>\n</tr>\n</tbody>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">b)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">contravvenga all’obbligo di presentarsi alle autorità o alla richiesta di fornire informazioni o di comparire per un colloquio personale concernente la procedura d’asilo durante un periodo di tempo ragionevole stabilito dal diritto nazionale; o</p>\n</td>\n</tr>\n</tbody>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">c)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">abbia presentato una domanda reiterata quale definita all’articolo 2, lettera q), della direttiva 2013/32/UE.</p>\n</td>\n</tr>\n</tbody>\n</table>\n<p class=\"oj-normal\">In relazione ai casi di cui alle lettere a) e b), se il richiedente viene rintracciato o si presenta volontariamente all’autorità competente, viene adottata una decisione debitamente motivata, basata sulle ragioni della scomparsa, nel ripristino della concessione di tutte le condizioni materiali di accoglienza revocate o ridotte o di una parte di esse.</p>\n</div>"], [2, "<div>\n<p class=\"oj-normal\">2.   Gli Stati membri possono inoltre ridurre le condizioni materiali di accoglienza quando possono accertare che il richiedente, senza un giustificato motivo, non ha presentato la domanda di protezione internazionale non appena ciò era ragionevolmente fattibile dopo il suo arrivo in tale Stato membro.</p>\n</div>"], [3, "<div>\n<p class=\"oj-normal\">3.   Gli Stati membri possono ridurre o revocare le condizioni materiali di accoglienza qualora un richiedente abbia occultato risorse finanziarie, beneficiando in tal modo indebitamente delle condizioni materiali di accoglienza.</p>\n</div>"], [4, "<div>\n<p class=\"oj-normal\">4.   Gli Stati membri possono prevedere sanzioni applicabili alle gravi violazioni delle regole dei centri di accoglienza nonché ai comportamenti gravemente violenti.</p>\n</div>"], [5, "<div>\n<p class=\"oj-normal\">5.   Le decisioni di ridurre o revocare le condizioni materiali di accoglienza o le sanzioni di cui ai paragrafi 1, 2, 3 e 4 del presente articolo, sono adottate in modo individuale, obiettivo e imparziale e sono motivate. Le decisioni sono basate sulla particolare situazione della persona interessata, specialmente per quanto concerne le persone contemplate all’articolo 21, tenendo conto del principio di proporzionalità. Gli Stati membri assicurano in qualsiasi circostanza l’accesso all’assistenza sanitaria ai sensi dell’articolo 19 e garantiscono un tenore di vita dignitoso per tutti i richiedenti.</p>\n</div>"], [6, "<div>\n<p class=\"oj-normal\">6.   Gli Stati membri provvedono a che le condizioni materiali di accoglienza non siano revocate o ridotte prima che sia adottata una decisione ai sensi del paragrafo 5.</p>\n</div>"]]}, "21": {"label": "Articolo 21", "heading": "Principio generale", "anchor": "art_21", "frags": [[null, "<p class=\"oj-normal\">Nelle misure nazionali di attuazione della presente direttiva, gli Stati membri tengono conto della specifica situazione di persone vulnerabili quali i minori, i minori non accompagnati, i disabili, gli anziani, le donne in stato di gravidanza, i genitori singoli con figli minori, le vittime della tratta degli esseri umani, le persone affette da gravi malattie o da disturbi mentali e le persone che hanno subito torture, stupri o altre forme gravi di violenza psicologica, fisica o sessuale, quali le vittime di mutilazioni genitali femminili.</p>"]]}, "22": {"label": "Articolo 22", "heading": "Valutazione delle particolari esigenze di accoglienza delle persone vulnerabili", "anchor": "art_22", "frags": [[1, "<div>\n<p class=\"oj-normal\">1.   Al fine di applicare efficacemente l’articolo 21, gli Stati membri valutano se il richiedente abbia esigenze di accoglienza particolari e precisano la natura delle stesse.</p>\n<p class=\"oj-normal\">Tale valutazione è avviata entro un termine ragionevole dopo la presentazione della domanda di protezione internazionale e può essere integrata nelle procedure nazionali esistenti. Gli Stati membri provvedono affinché tali esigenze di accoglienza particolari siano affrontate, secondo le disposizioni della presente direttiva, anche se si manifestano in una fase successiva della procedura di asilo.</p>\n<p class=\"oj-normal\">Gli Stati membri assicurano che il sostegno fornito ai richiedenti con esigenze di accoglienza particolari ai sensi della presente direttiva tenga conto delle loro esigenze di accoglienza particolari durante l’intera procedura di asilo e provvedono a un appropriato controllo della loro situazione.</p>\n</div>"], [2, "<div>\n<p class=\"oj-normal\">2.   La valutazione di cui al paragrafo 1 non deve assumere la forma di una procedura amministrativa.</p>\n</div>"], [3, "<div>\n<p class=\"oj-normal\">3.   Solo le persone vulnerabili ai sensi dell’articolo 21 possono essere considerate come persone con esigenze di accoglienza particolari e possono pertanto beneficiare del sostegno particolare previsto conformemente alla presente direttiva.</p>\n</div>"], [4, "<div>\n<p class=\"oj-normal\">4.   La valutazione di cui al paragrafo 1 non pregiudica la valutazione delle esigenze di protezione internazionale di cui alla direttiva 2011/95/UE.</p>\n</div>"]]}, "23": {"label": "Articolo 23", "heading": "Minori", "anchor": "art_23", "frags": [[1, "<div>\n<p class=\"oj-normal\">1.   L’interesse superiore del minore costituisce un criterio fondamentale nell’attuazione, da parte degli Stati membri, delle disposizioni della presente direttiva concernenti i minori. Gli Stati membri assicurano un livello di vita adeguato allo sviluppo fisico, mentale, spirituale, morale e sociale del minore.</p>\n</div>"], [2, "<div>\n<p class=\"oj-normal\">2.   Nel valutare l’interesse superiore del minore, gli Stati membri tengono debito conto, in particolare, dei seguenti fattori:</p>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">a)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">la possibilità di ricongiungimento familiare;</p>\n</td>\n</tr>\n</tbody>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">b)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">il benessere e lo sviluppo sociale del minore, con particolare riguardo ai trascorsi del minore;</p>\n</td>\n</tr>\n</tbody>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">c)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">le considerazioni in ordine all’incolumità e alla sicurezza, in particolare se sussiste il rischio che il minore sia vittima della tratta di esseri umani;</p>\n</td>\n</tr>\n</tbody>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">d)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">l’opinione del minore, secondo la sua età e maturità.</p>\n</td>\n</tr>\n</tbody>\n</table>\n</div>"], [3, "<div>\n<p class=\"oj-normal\">3.   Gli Stati membri provvedono affinché i minori possano svolgere attività di tempo libero, compresi il gioco e le attività ricreative consone alla loro età, all’interno dei locali e dei centri di accoglienza di cui all’articolo 18, paragrafo 1, lettere a) e b), e attività all’aria aperta.</p>\n</div>"], [4, "<div>\n<p class=\"oj-normal\">4.   Gli Stati membri garantiscono l’accesso ai servizi di riabilitazione per i minori che abbiano subito qualsiasi forma di abuso, negligenza, sfruttamento, tortura, trattamento crudele, disumano o degradante o che abbiano sofferto gli effetti di un conflitto armato e assicurano che siano predisposte, ove necessario, appropriate misure di assistenza psichica e una consulenza qualificata.</p>\n</div>"], [5, "<div>\n<p class=\"oj-normal\">5.   Gli Stati membri provvedono, affinché i figli minori dei richiedenti e i richiedenti minori siano alloggiati assieme ai loro genitori, i fratelli minori non coniugati o gli adulti che ne abbiano la responsabilità per legge o per la prassi dello Stato membro interessato, purché sia nell’interesse superiore dei minori in questione.</p>\n</div>"]]}, "24": {"label": "Articolo 24", "heading": "Minori non accompagnati", "anchor": "art_24", "frags": [[1, "<div>\n<p class=\"oj-normal\">1.   Gli Stati membri adottano quanto prima misure atte ad assicurare che un rappresentante rappresenti e assista il minore non accompagnato per consentirgli di godere dei diritti e assolvere agli obblighi previsti dalla presente direttiva. Il minore non accompagnato è immediatamente informato della nomina del rappresentante. Il rappresentante svolge i suoi doveri in conformità del principio dell’interesse superiore del minore, come prescrive l’articolo 23, paragrafo 2, e possiede le competenze necessarie a tale scopo. Al fine di assicurare il benessere e lo sviluppo sociale del minore di cui all’articolo 23, paragrafo 2, lettera b), la persona che funge da rappresentante è sostituita solo in caso di necessità. Le organizzazioni o gli individui i cui interessi contrastano o possono potenzialmente contrastare con quelli del minore non accompagnato non sono ammissibili ad assumere il ruolo di rappresentanti.</p>\n<p class=\"oj-normal\">Le autorità competenti effettuano periodiche verifiche, anche per quanto riguarda la disponibilità dei mezzi necessari per rappresentare il minore non accompagnato.</p>\n</div>"], [2, "<div>\n<p class=\"oj-normal\">2.   I minori non accompagnati che presentano domanda di protezione internazionale, dal momento in cui entrano nel territorio dello Stato membro in cui la domanda di protezione internazionale è stata presentata o é esaminata sino al momento in cui ne debbono uscire, sono alloggiati:</p>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">a)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">presso familiari adulti;</p>\n</td>\n</tr>\n</tbody>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">b)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">presso una famiglia affidataria;</p>\n</td>\n</tr>\n</tbody>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">c)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">in centri di accoglienza che dispongano di specifiche strutture per i minori;</p>\n</td>\n</tr>\n</tbody>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">d)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">in altri alloggi idonei per i minori.</p>\n</td>\n</tr>\n</tbody>\n</table>\n<p class=\"oj-normal\">Gli Stati membri possono alloggiare i minori non accompagnati che abbiano compiuto i 16 anni in centri di accoglienza per adulti richiedenti, se è nel loro interesse superiore, come prescrive l’articolo 23, paragrafo 2.</p>\n<p class=\"oj-normal\">Per quanto possibile i fratelli sono alloggiati insieme, tenendo conto dell’interesse superiore del minore in questione e, in particolare, della sua età e del grado di maturità. I cambi di residenza di minori non accompagnati sono limitati al minimo.</p>\n</div>"], [3, "<div>\n<p class=\"oj-normal\">3.   Gli Stati membri iniziano a rintracciare quanto prima i familiari del minore non accompagnato, se necessario con l’assistenza di organizzazioni internazionali o altre organizzazioni competenti, non appena sia manifestata la volontà di chiedere la protezione internazionale, sempre tutelandone l’interesse superiore. Nei casi in cui sussistano rischi per la vita o l’integrità del minore o dei suoi parenti stretti, in particolare se questi sono rimasti nel paese di origine, la raccolta, il trattamento e la diffusione delle informazioni relative a queste persone sono effettuate in via confidenziale, in modo da non mettere in pericolo la loro sicurezza.</p>\n</div>"], [4, "<div>\n<p class=\"oj-normal\">4.   Le persone che si occupano di minori non accompagnati hanno ricevuto e continuano a ricevere una specifica formazione in merito alle particolari esigenze degli stessi e sono soggette, conformemente a quanto stabilito dal diritto nazionale, all’obbligo di riservatezza relativamente alle informazioni di cui dovessero venire a conoscenza durante l’attività da loro svolta.</p>\n</div>"]]}, "25": {"label": "Articolo 25", "heading": "Vittime di tortura e di violenza", "anchor": "art_25", "frags": [[1, "<div>\n<p class=\"oj-normal\">1.   Gli Stati membri provvedono affinché le persone che hanno subito torture, stupri o altri gravi atti di violenza ricevano il necessario trattamento per il danno provocato da tali atti, e accedano in particolare ad assistenza o cure mediche e psicologiche appropriate.</p>\n</div>"], [2, "<div>\n<p class=\"oj-normal\">2.   Le persone che si occupano delle vittime di torture, stupri o altri gravi atti di violenza hanno ricevuto e continuano a ricevere una specifica formazione in merito alle esigenze delle stesse e sono soggette, conformemente a quanto stabilito dal diritto nazionale, all’obbligo di riservatezza relativamente alle informazioni di cui dovessero venire a conoscenza nello svolgimento della loro attività.</p>\n</div>"]]}, "26": {"label": "Articolo 26", "heading": "Mezzi di ricorso", "anchor": "art_26", "frags": [[1, "<div>\n<p class=\"oj-normal\">1.   Gli Stati membri garantiscono che le decisioni relative alla concessione, alla revoca o alla riduzione di benefici ai sensi della presente direttiva o le decisioni adottate ai sensi dell’articolo 7 che riguardano individualmente i richiedenti possano essere impugnate secondo le modalità stabilite dal diritto nazionale. Almeno in ultimo grado è garantita la possibilità di ricorso o riesame, in fatto e in diritto, dinanzi a un’autorità giurisdizionale.</p>\n</div>"], [2, "<div>\n<p class=\"oj-normal\">2.   Nei casi di ricorso o riesame dinanzi a un’autorità giurisdizionale di cui al paragrafo 1, gli Stati membri garantiscono l’accesso gratuito all’assistenza e alla rappresentanza legali su richiesta, nella misura in cui tale assistenza e rappresentanza legali sono necessarie per garantire l’accesso effettivo alla giustizia. Ciò include, come minimo, la preparazione dei documenti procedurali necessari e la partecipazione all’udienza dinanzi alle autorità giurisdizionali a nome del richiedente.</p>\n<p class=\"oj-normal\">L’assistenza e la rappresentanza legali gratuite sono fornite da persone adeguatamente qualificate, autorizzate o riconosciute ai sensi del diritto nazionale, i cui interessi non contrastano o non possono potenzialmente contrastare con quelli del richiedente.</p>\n</div>"], [3, "<div>\n<p class=\"oj-normal\">3.   Gli Stati membri possono anche disporre che l’assistenza e la rappresentanza legali gratuite siano concesse:</p>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">a)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">soltanto a chi non disponga delle risorse necessarie; e/o</p>\n</td>\n</tr>\n</tbody>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">b)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">soltanto mediante i servizi forniti da avvocati o altri consulenti legali che sono specificamente designati dal diritto nazionale ad assistere e rappresentare i richiedenti.</p>\n</td>\n</tr>\n</tbody>\n</table>\n<p class=\"oj-normal\">Gli Stati membri possono disporre che l’assistenza e la rappresentanza legali gratuite non siano accordate se un’autorità competente ritiene che il ricorso o la revisione non abbiano prospettive concrete di successo. In tal caso, gli Stati membri garantiscono che l’assistenza e la rappresentanza legali non siano oggetto di restrizioni arbitrarie e che non sia ostacolato l’accesso effettivo del richiedente alla giustizia.</p>\n</div>"], [4, "<div>\n<p class=\"oj-normal\">4.   Gli Stati membri possono altresì:</p>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">a)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">imporre limiti monetari e/o temporali alla prestazione di assistenza e rappresentanza legali gratuite, purché essi non costituiscano restrizioni arbitrarie all’assistenza e alla rappresentanza legali;</p>\n</td>\n</tr>\n</tbody>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">b)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">prevedere, per quanto riguarda gli onorari e le altre spese, che il trattamento concesso ai richiedenti non sia più favorevole di quello di norma concesso ai propri cittadini per questioni che rientrano nell’assistenza legale.</p>\n</td>\n</tr>\n</tbody>\n</table>\n</div>"], [5, "<div>\n<p class=\"oj-normal\">5.   Gli Stati membri possono esigere un rimborso integrale o parziale delle spese sostenute, allorché vi sia stato un considerevole miglioramento delle condizioni finanziarie del richiedente o se la decisione di accordare tali prestazioni è stata adottata in base a informazioni false fornite dal richiedente.</p>\n</div>"], [6, "<div>\n<p class=\"oj-normal\">6.   Le modalità di accesso all’assistenza e alla rappresentanza legali sono stabilite dal diritto nazionale.</p>\n</div>"]]}, "27": {"label": "Articolo 27", "heading": "Autorità competenti", "anchor": "art_27", "frags": [[null, "<p class=\"oj-normal\">Gli Stati membri notificano alla Commissione le autorità responsabili dell’esecuzione degli obblighi risultanti dalla presente direttiva. Gli Stati membri informano la Commissione di qualsiasi cambiamento in ordine alle autorità designate.</p>"]]}, "28": {"label": "Articolo 28", "heading": "Sistema di orientamento, sorveglianza e controllo", "anchor": "art_28", "frags": [[1, "<div>\n<p class=\"oj-normal\">1.   Gli Stati membri, nel debito rispetto della loro struttura costituzionale, mettono in atto opportuni meccanismi con cui assicurare adeguate misure di orientamento, sorveglianza e controllo del livello delle condizioni di accoglienza.</p>\n</div>"], [2, "<div>\n<p class=\"oj-normal\">2.   Gli Stati membri comunicano alla Commissione le pertinenti informazioni usando il modulo di cui all’allegato I entro il 20 luglio 2016.</p>\n</div>"]]}, "29": {"label": "Articolo 29", "heading": "Personale e risorse", "anchor": "art_29", "frags": [[1, "<div>\n<p class=\"oj-normal\">1.   Gli Stati membri adottano le misure adeguate per garantire che le autorità competenti e le organizzazioni che danno attuazione alla presente direttiva abbiano ricevuto la necessaria formazione di base riguardo alle esigenze dei richiedenti di entrambi i sessi.</p>\n</div>"], [2, "<div>\n<p class=\"oj-normal\">2.   Gli Stati membri stanziano le risorse necessarie per le misure nazionali di attuazione della presente direttiva.</p>\n</div>"]]}, "30": {"label": "Articolo 30", "heading": "Relazioni", "anchor": "art_30", "frags": [[null, "<p class=\"oj-normal\">Entro il 20 luglio 2017 la Commissione presenta al Parlamento europeo e al Consiglio una relazione sull’applicazione della presente direttiva, proponendo all’occorrenza le necessarie modifiche.</p>"], [null, "<p class=\"oj-normal\">Gli Stati membri trasmettono alla Commissione tutte le informazioni utili ai fini della relazione entro il 20 luglio 2016.</p>"], [null, "<p class=\"oj-normal\">Successivamente alla prima relazione, la Commissione riferisce al Parlamento europeo e al Consiglio almeno ogni cinque anni sull’applicazione della presente direttiva.</p>"]]}, "31": {"label": "Articolo 31", "heading": "Recepimento", "anchor": "art_31", "frags": [[1, "<div>\n<p class=\"oj-normal\">1.   Gli Stati membri adottano le disposizioni legislative, regolamentari e amministrative necessarie per conformarsi agli articoli da 1 a 12, da 14 a 28 e 30 e all’allegato I entro il 20 luglio 2015. Essi comunicano immediatamente alla Commissione il testo di tali disposizioni.</p>\n<p class=\"oj-normal\">Quando gli Stati membri adottano tali disposizioni, queste contengono un riferimento alla presente direttiva o sono corredate di un siffatto riferimento all’atto della pubblicazione ufficiale. Esse recano altresì un’indicazione da cui risulti che i riferimenti alla direttiva abrogata dalla presente direttiva, contenuti in disposizioni legislative, regolamentari e amministrative previgenti, devono intendersi come riferimenti fatti alla presente direttiva. Le modalità di tale riferimento nonché la formulazione di detta indicazione sono decise dagli Stati membri.</p>\n</div>"], [2, "<div>\n<p class=\"oj-normal\">2.   Gli Stati membri trasmettono alla Commissione il testo delle principali disposizioni nazionali che essi adottano nel settore contemplato dalla presente direttiva.</p>\n</div>"]]}, "32": {"label": "Articolo 32", "heading": "Abrogazione", "anchor": "art_32", "frags": [[null, "<p class=\"oj-normal\">La direttiva 2003/9/CE è abrogata per gli Stati membri vincolati dalla presente direttiva con effetto dal 21 luglio 2015, fatti salvi gli obblighi degli Stati membri relativi al termine di recepimento nel diritto interno di cui all’allegato II, parte B.</p>"], [null, "<p class=\"oj-normal\">I riferimenti alla direttiva abrogata si intendono fatti alla presente direttiva e vanno letti secondo la tavola di concordanza di cui all’allegato III.</p>"]]}, "33": {"label": "Articolo 33", "heading": "Entrata in vigore e applicazione", "anchor": "art_33", "frags": [[null, "<p class=\"oj-normal\">La presente direttiva entra in vigore il ventesimo giorno successivo alla pubblicazione nella <span class=\"oj-italic\">Gazzetta ufficiale dell’Unione europea</span>.</p>"], [null, "<p class=\"oj-normal\">Gli articoli 13 e 29 si applicano dal 21 luglio 2015.</p>"]]}, "34": {"label": "Articolo 34", "heading": "Destinatari", "anchor": "art_34", "frags": [[null, "<p class=\"oj-normal\">Gli Stati membri sono destinatari della presente direttiva in conformità dei trattati.</p>"]]}}, "recitals": {}};